import React, { useState } from 'react';
import { ImagePlus } from 'lucide-react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    producto: '', precioViejo: '', precioNuevo: '', peso: '', stock: '', imagen: ''
  });

  // Maneja la conversión de imagen a Base64 para guardar en LocalStorage
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, imagen: reader.result });
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave({ 
      ...formData, 
      id: Date.now(),
      precioViejo: Number(formData.precioViejo),
      precioNuevo: Number(formData.precioNuevo),
      peso: parseFloat(formData.peso),
      stock: parseInt(formData.stock) 
    });
  };

  return (
    <div style={formCard}>
      <h3 style={{marginTop: 0, color: '#1e293b'}}>Publicar Producto</h3>
      <form onSubmit={handleSubmit}>
        {/* Selector de Imagen */}
        <div style={imageUploadContainer}>
          {formData.imagen ? (
            <img src={formData.imagen} alt="Preview" style={previewImage} />
          ) : (
            <label style={uploadLabel}>
              <ImagePlus size={30} />
              <span>Subir Foto</span>
              <input type="file" accept="image/*" onChange={handleImageChange} style={{display: 'none'}} />
            </label>
          )}
        </div>

        <input placeholder="Nombre del producto" style={inputStyle} required 
          onChange={e => setFormData({...formData, producto: e.target.value})} />
        
        <div style={{ display: 'flex', gap: '10px' }}>
          <input type="number" placeholder="Precio Normal" style={inputStyle} required 
            onChange={e => setFormData({...formData, precioViejo: e.target.value})} />
          <input type="number" placeholder="Precio Oferta" style={inputStyle} required 
            onChange={e => setFormData({...formData, precioNuevo: e.target.value})} />
        </div>

        <div style={rowStyle}>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}>Peso (kg) - Ej: 0.165</label>
            <input type="number" step="0.001" placeholder="0.000" style={inputStyle} required 
              onChange={e => setFormData({...formData, peso: e.target.value})} />
          </div>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}>Unidades Stock</label>
            <input type="number" placeholder="Ej: 20" style={inputStyle} required 
              onChange={e => setFormData({...formData, stock: e.target.value})} />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '10px' }}>
          <button type="submit" style={btnSave}>Publicar Oferta</button>
          <button type="button" onClick={onCancel} style={btnCancel}>Cancelar</button>
        </div>
      </form>
    </div>
  );
};

// --- ESTILOS EXTRA PARA IMAGEN ---
const imageUploadContainer = { width: '100%', height: '150px', background: '#f1f5f9', borderRadius: '12px', marginBottom: '15px', overflow: 'hidden', border: '2px dashed #cbd5e1' };
const uploadLabel = { width: '100%', height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: '#64748b', gap: '10px' };
const previewImage = { width: '100%', height: '100%', objectFit: 'cover' };
const formCard = { background: 'white', padding: '25px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '10px', borderRadius: '8px', border: '1px solid #e2e8f0', boxSizing: 'border-box' };
const rowStyle = { display: 'flex', gap: '15px', marginBottom: '10px', background: '#f8fafc', padding: '10px', borderRadius: '10px' };
const miniLabel = { fontSize: '0.7rem', color: '#94a3b8', display: 'block', marginBottom: '4px', fontWeight: 'bold' };
const btnSave = { flex: 1, padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { flex: 1, padding: '12px', background: '#f1f5f9', color: '#64748b', border: 'none', borderRadius: '10px', cursor: 'pointer' };

export default FormularioOferta;
